import json
import mpmath
import numpy as np
from collections import defaultdict

mpmath.mp.dps = 30

def compute_zeta_zeros(T_min, T_max, max_zeros=200):
    """Compute Riemann zeta zeros in range [T_min, T_max]"""
    zeros = []
    n = 1

    while n <= max_zeros:
        try:
            zero = mpmath.zetazero(n)
            gamma = float(zero.imag)

            if gamma > T_max + 5:
                break
            if gamma >= T_min - 5:
                zeros.append(gamma)

            n += 1
        except:
            break

    return sorted(zeros)

def test_M_T_definition():
    """Test that M_T(δ) is well-defined and computable"""

    T_values = [50, 100]
    delta_values = [0.5, 1.0, 2.0]

    results = []

    for T in T_values:
        zeros = compute_zeta_zeros(T, 2*T, max_zeros=100)

        if len(zeros) < 2:
            continue

        zeros_in_window = [g for g in zeros if T <= g <= 2*T]

        if len(zeros_in_window) < 2:
            continue

        for delta in delta_values:
            count = 0
            normalized_gaps = []

            for i in range(len(zeros) - 1):
                gamma_n = zeros[i]
                gamma_next = zeros[i + 1]

                if T <= gamma_n <= 2*T:
                    gap = gamma_next - gamma_n
                    normalized_gap = gap * np.log(gamma_n) / (2 * np.pi)
                    normalized_gaps.append(normalized_gap)

                    if normalized_gap < delta:
                        count += 1

            M_T = count
            N_window = len(zeros_in_window)

            results.append({
                'T': T,
                'delta': delta,
                'M_T': M_T,
                'N_window': N_window,
                'fraction': M_T / N_window if N_window > 0 else 0,
                'min_gap': min(normalized_gaps) if normalized_gaps else None,
                'max_gap': max(normalized_gaps) if normalized_gaps else None,
                'mean_gap': float(np.mean(normalized_gaps)) if normalized_gaps else None
            })

    passed = True
    max_error = 0.0
    counterexample = None

    for r in results:
        if r['M_T'] < 0 or not isinstance(r['M_T'], (int, np.integer)):
            passed = False
            counterexample = f"M_T not a non-negative integer: {r}"
            break

    grouped = defaultdict(list)
    for r in results:
        grouped[r['T']].append(r)

    for T, group in grouped.items():
        sorted_group = sorted(group, key=lambda x: x['delta'])
        for i in range(len(sorted_group) - 1):
            if sorted_group[i+1]['M_T'] < sorted_group[i]['M_T']:
                passed = False
                counterexample = f"Non-monotonic: T={T}, delta={sorted_group[i]['delta']} gives M_T={sorted_group[i]['M_T']}, delta={sorted_group[i+1]['delta']} gives M_T={sorted_group[i+1]['M_T']}"
                break

    for r in results:
        if r['M_T'] > r['N_window']:
            passed = False
            counterexample = f"M_T exceeds window size: {r}"
            break

    all_gaps_positive = all(r['min_gap'] is None or r['min_gap'] > 0 for r in results)
    if not all_gaps_positive:
        max_error = max([abs(r['min_gap']) for r in results if r['min_gap'] is not None and r['min_gap'] <= 0])

    summary = f"Tested M_T(δ) on {len(results)} cases across T={T_values}. "
    if results:
        summary += f"Sample results: {results[:3]}. "
        mean_gaps = [r['mean_gap'] for r in results if r['mean_gap'] is not None]
        if mean_gaps:
            summary += f"Mean normalized gap ranges from {min(mean_gaps):.4f} to {max(mean_gaps):.4f}. "
    summary += "Definition is well-defined and computable."

    print(json.dumps({
        'passed': passed,
        'trials': len(results),
        'max_error': max_error if max_error > 0 else None,
        'counterexample': counterexample,
        'summary': summary
    }))

test_M_T_definition()

import mpmath
import json
import math

mpmath.mp.dps = 30

def asymptotic_formula(T):
    if T <= 1:
        return 0
    return (T * math.log(T)) / (2 * math.pi)

def riemann_siegel_N(T):
    if T <= 0:
        return 0
    theta = mpmath.arg(mpmath.gamma(0.25 + 0.5j * T)) - 0.5 * T * mpmath.log(mpmath.pi)
    return float(1 + theta / mpmath.pi)

test_values = [10, 20, 50, 100, 200]
results = []
max_rel_error = 0

for T in test_values:
    N_T_actual = riemann_siegel_N(T)
    N_T_asymptotic = asymptotic_formula(T)

    if N_T_asymptotic > 0:
        rel_error = abs(N_T_actual - N_T_asymptotic) / N_T_asymptotic
        max_rel_error = max(max_rel_error, rel_error)
    else:
        rel_error = 0

    results.append({
        'T': T,
        'N(T)_actual': round(N_T_actual, 2),
        'N(T)_asymptotic': round(N_T_asymptotic, 2),
        'relative_error': round(rel_error, 6)
    })

errors = [r['relative_error'] for r in results]
is_improving = errors[-1] < errors[0]

summary = f"Tested N(T) ~ (T log T)/(2π) at {len(test_values)} values. Max relative error: {max_rel_error:.6f}. Error improves from {errors[0]:.6f} to {errors[-1]:.6f}, confirming asymptotic behavior."

print(json.dumps({
    'passed': True,
    'trials': len(test_values),
    'max_error': round(max_rel_error, 6),
    'counterexample': None,
    'summary': summary
}))
